1	const PROCESSING_FEE = 5;
2	const BLOCK_OF_THREE_SIZE = 3;
3	const BLOCK_OF_THREE_PREMIUM = 60;
4	const CURSED_SURCHARGE = 0.5;
5	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
6	const HIGH_ENCHANTMENT_THRESHOLD = 5;
7	const FIRST_INSURANCE_SURCHARGE = 0.1;
8	const LOYALTY_DISCOUNT = -0.2;
9	const LOYALTY_YEARS_THRESHOLD = 2;
10	const FOLLOW_UP_DISCOUNT = -0.15;
11	const DEDUCTIBLE = 100;
12	const CAP_MULTIPLIER = 2;
13	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
14	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
15	const FULL_REIMBURSEMENT_RATE = 1;
16	
17	const BASE_PREMIUM: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	  rune: 25,
23	  moonstone: 25,
24	};
25	
26	const INSURANCE_VALUE_MULTIPLIER = 10;
27	
28	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
29	
30	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
31	type Customer = { yearsWithMHPCO?: number; firstInsurance?: boolean };
32	type Damage = { itemType: string; amount: number };
33	type Incident = { cause: string; damages: Damage[] };
34	type QuoteStep = { op: "quote"; items: Item[] };
35	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
36	type Step = QuoteStep | ClaimStep;
37	type Scenario = { customer: Customer; steps: Step[] };
38	
39	type Policy = { items: Item[]; cap: number };
40	
41	const basePremiumFor = (type: string): number => {
42	  const value = BASE_PREMIUM[type];
43	  if (value === undefined) throw new Error(`unknown item type: ${type}`);
44	  return value;
45	};
46	
47	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
48	
49	const isMainItem = (item: Item): boolean => !isComponent(item);
50	
51	const countBy = <T>(xs: T[], keyOf: (x: T) => string): Map<string, number> =>
52	  xs.reduce((m, x) => m.set(keyOf(x), (m.get(keyOf(x)) ?? 0) + 1), new Map<string, number>());
53	
54	const componentGroupPremium = (type: string, count: number): number =>
55	  count === BLOCK_OF_THREE_SIZE ? BLOCK_OF_THREE_PREMIUM : count * basePremiumFor(type);
56	
57	const componentsPremium = (items: Item[]): number =>
58	  Array.from(countBy(items.filter(isComponent), (i) => i.type))
59	    .reduce((sum, [type, count]) => sum + componentGroupPremium(type, count), 0);
60	
61	const isHighlyEnchanted = (item: Item): boolean =>
62	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
63	
64	const rateWhen = (applies: boolean, rate: number): number => (applies ? rate : 0);
65	
66	const itemRateAdjustment = (item: Item): number =>
67	  rateWhen(item.cursed === true, CURSED_SURCHARGE) +
68	  rateWhen(isHighlyEnchanted(item), HIGH_ENCHANTMENT_SURCHARGE);
69	
70	const itemPremium = (item: Item): number =>
71	  basePremiumFor(item.type) * (1 + itemRateAdjustment(item));
72	
73	type PremiumBreakdown = { base: number; withSurcharges: number };
74	
75	const addBreakdowns = (a: PremiumBreakdown, b: PremiumBreakdown): PremiumBreakdown => ({
76	  base: a.base + b.base,
77	  withSurcharges: a.withSurcharges + b.withSurcharges,
78	});
79	
80	const mainItemBreakdown = (item: Item): PremiumBreakdown => ({
81	  base: basePremiumFor(item.type),
82	  withSurcharges: itemPremium(item),
83	});
84	
85	const componentsBreakdown = (items: Item[]): PremiumBreakdown => {
86	  const total = componentsPremium(items);
87	  return { base: total, withSurcharges: total };
88	};
89	
90	const itemsBreakdown = (items: Item[]): PremiumBreakdown =>
91	  items
92	    .filter(isMainItem)
93	    .map(mainItemBreakdown)
94	    .reduce(addBreakdowns, componentsBreakdown(items));
95	
96	const isLongStanding = (customer: Customer): boolean =>
97	  (customer.yearsWithMHPCO ?? 0) >= LOYALTY_YEARS_THRESHOLD;
98	
99	const policyRateAdjustment = (customer: Customer, isFollowUp: boolean): number =>
100	  rateWhen(customer.firstInsurance === true, FIRST_INSURANCE_SURCHARGE) +
101	  rateWhen(isLongStanding(customer), LOYALTY_DISCOUNT) +
102	  rateWhen(isFollowUp, FOLLOW_UP_DISCOUNT);
103	
104	const FLOATING_POINT_EPSILON = 1e-9;
105	
106	const roundUpInOurFavor = (amount: number): number =>
107	  Math.ceil(amount - FLOATING_POINT_EPSILON);
108	
109	const roundDownInOurFavor = (amount: number): number =>
110	  Math.floor(amount + FLOATING_POINT_EPSILON);
111	
112	const policyPremium = (customer: Customer, items: Item[], isFollowUp: boolean): number => {
113	  const { base, withSurcharges } = itemsBreakdown(items);
114	  return withSurcharges + base * policyRateAdjustment(customer, isFollowUp) + PROCESSING_FEE;
115	};
116	
117	const quoteResult = (customer: Customer, items: Item[], isFollowUp: boolean): { premium: number } => ({
118	  premium: roundUpInOurFavor(policyPremium(customer, items, isFollowUp)),
119	});
120	
121	const insuranceValueFor = (type: string): number => basePremiumFor(type) * INSURANCE_VALUE_MULTIPLIER;
122	
123	const insuranceSumFor = (items: Item[]): number =>
124	  items.reduce((sum, item) => sum + insuranceValueFor(item.type), 0);
125	
126	const reimbursementRate = (item: Item | undefined): number =>
127	  (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
128	    ? HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
129	    : FULL_REIMBURSEMENT_RATE;
130	
131	const findInsuredItem = (items: Item[], type: string): Item | undefined =>
132	  items.find((i) => i.type === type);
133	
134	const damagePayout = (damage: Damage, items: Item[]): number =>
135	  Math.max(0, damage.amount * reimbursementRate(findInsuredItem(items, damage.itemType)) - DEDUCTIBLE);
136	
137	const totalRawPayout = (damages: Damage[], items: Item[]): number =>
138	  damages.reduce((sum, d) => sum + damagePayout(d, items), 0);
139	
140	const openPolicy = (items: Item[]): Policy => ({
141	  items,
142	  cap: insuranceSumFor(items) * CAP_MULTIPLIER,
143	});
144	
145	const countOf = (counts: Map<string, number>, key: string): number =>
146	  counts.get(key) ?? 0;
147	
148	const validateDamageCounts = (policy: Policy, damages: Damage[]): void => {
149	  const insuredCounts = countBy(policy.items, (i) => i.type);
150	  const damageCounts = countBy(damages, (d) => d.itemType);
151	  damageCounts.forEach((damageCount, type) => {
152	    if (damageCount > countOf(insuredCounts, type))
153	      throw new Error(`damage references more ${type} items than insured`);
154	  });
155	};
156	
157	const validateDamageAmounts = (damages: Damage[]): void => {
158	  damages.forEach((d) => {
159	    if (d.amount < 0) throw new Error(`negative damage amount: ${d.amount}`);
160	  });
161	};
162	
163	const settleClaim = (policy: Policy, incident: Incident): { payout: number; remainingCap: number } => {
164	  validateDamageAmounts(incident.damages);
165	  validateDamageCounts(policy, incident.damages);
166	  const payout = roundDownInOurFavor(Math.min(totalRawPayout(incident.damages, policy.items), policy.cap));
167	  policy.cap -= payout;
168	  return { payout, remainingCap: policy.cap };
169	};
170	
171	type QuoteResult = { premium: number };
172	type ClaimResult = { payout: number; remainingCap: number };
173	type StepResult = QuoteResult | ClaimResult;
174	
175	const processStep = (customer: Customer, policies: Policy[]) =>
176	  (step: Step, stepIndex: number): StepResult => {
177	    if (step.op === "quote") {
178	      policies[stepIndex] = openPolicy(step.items);
179	      return quoteResult(customer, step.items, stepIndex > 0);
180	    }
181	    return settleClaim(policies[step.policy], step.incident);
182	  };
183	
184	export const runScenario = (input: unknown): { results: StepResult[] } => {
185	  const { customer, steps } = input as Scenario;
186	  const policies: Policy[] = [];
187	  return { results: steps.map(processStep(customer, policies)) };
188	};
